const body    = $input.first().json.body ?? $input.first().json;
const data    = body.data    ?? body;
const key     = data.key     ?? body.key     ?? {};
const message = data.message ?? body.message ?? {};

if (key.fromMe === true) return [];
if ((key.remoteJid ?? '').includes('@g.us')) return [];

const from = (key.remoteJid ?? '')
  .replace('@s.whatsapp.net', '')
  .replace('@g.us', '');

if (!from || from.length < 5) return [];

const texto    = (message.conversation ?? message.extendedTextMessage?.text ?? message.buttonsResponseMessage?.selectedDisplayText ?? message.listResponseMessage?.singleSelectReply?.selectedRowId ?? '').trim();
const buttonId = message.buttonsResponseMessage?.selectedButtonId ?? message.listResponseMessage?.singleSelectReply?.selectedRowId ?? null;
const instance = body.instance ?? data.instance ?? 'N8N-Portaria';

return [{ json: { from, texto, buttonId, instance } }];

const p = $('Parsear Mensagem').item.json;
let moradores = [], sessoes = [];
try { const t = $('GET Morador').item.json.data ?? $('GET Morador').item.json; moradores = typeof t === 'string' ? JSON.parse(t) : (Array.isArray(t) ? t : []); } catch(e) { moradores = []; }
try { const t = $('GET Sessao').item.json.data  ?? $('GET Sessao').item.json;  sessoes   = typeof t === 'string' ? JSON.parse(t) : (Array.isArray(t) ? t : []); } catch(e) { sessoes   = []; }
const m = moradores[0] ?? null;
const s = sessoes[0]   ?? null;
return [{ json: {
  from:              p.from,
  texto:             p.texto,
  buttonId:          p.buttonId,
  instance:          p.instance,
  moradorEncontrado: m !== null,
  moradorId:         m?.id          ?? null,
  moradorNome:       m?.nome        ?? null,
  moradorApto:       m?.apartamento ?? null,
  moradorBloco:      m?.bloco       ?? null,
  sessaoEtapa:       s?.etapa       ?? null,
  sessaoDados:       s?.dados       ?? {}
} }];

const d = $json;
const etapa = d.sessaoEtapa, texto = d.texto ?? '', dados = d.sessaoDados ?? {};
let nd = { ...dados }, prox = null, resp = '', ok = false;

if (!etapa) {
  resp = 'Olá! 👋 Não encontrei seu cadastro.\n\nVamos fazer seu registro rapidinho! 😊\n\nQual é o seu *nome completo*?';
  prox = 'aguardando_nome'; nd = {};
} else if (etapa === 'aguardando_nome') {
  if (texto.length < 3) { resp = '⚠️ Nome muito curto. Digite seu nome completo.'; prox = 'aguardando_nome'; }
  else { nd.nome = texto; resp = `Ótimo, *${texto}*! 🏠\n\nQual é o número do seu *apartamento*?`; prox = 'aguardando_apto'; }
} else if (etapa === 'aguardando_apto') {
  if (texto.length < 1) { resp = '⚠️ Informe o número do apartamento.'; prox = 'aguardando_apto'; }
  else { nd.apto = texto; resp = `Perfeito! 🏢\n\nQual é o *bloco*?\n_(Ex: A, B — ou "Único" se não houver)_`; prox = 'aguardando_bloco'; }
} else if (etapa === 'aguardando_bloco') {
  nd.bloco = texto; ok = true;
  resp = `✅ *Cadastro realizado!*\n\n👤 ${nd.nome}\n🏠 Ap. ${nd.apto} - Bloco ${nd.bloco}\n\nBem-vindo(a)! 🎉\n\nEnvie qualquer mensagem para o menu.`;
}

return [{ json: { from: d.from, instance: d.instance, resp, prox, nd: JSON.stringify(nd), ok, nome: nd.nome ?? '', apto: nd.apto ?? '', bloco: nd.bloco ?? '' } }];

const d = $json;
const t = (d.texto ?? '').trim();
const upper = t.toUpperCase();
const b = d.buttonId;
const etapa = d.sessaoEtapa ?? '';

let rota = 'menu';
if (upper === 'CANCELAR') rota = 'cancelar';
else if (etapa.startsWith('visitante_')) rota = 'visitantes';
else if (etapa.startsWith('ocorrencia_')) rota = 'ocorrencias';
else if (etapa.startsWith('servico_')) rota = 'servicos';
else if (b === 'btn_encomendas' || t === '1') rota = 'encomendas';
else if (b === 'btn_visitantes' || t === '2') rota = 'visitantes';
else if (b === 'btn_servicos' || t === '3') rota = 'servicos';
else if (etapa.startsWith('reserva_')) rota = 'reservas';
else if (b === 'btn_reservas' || t === '4') rota = 'reservas';
else if (b === 'btn_ocorrencias' || t === '5') rota = 'ocorrencias';
else if (upper.startsWith('RETIREI')) rota = 'retirada';

return [{ json: { ...d, rota } }];

const raw = $input.first().json.data ?? $input.first().json;
let lista = [];
try { lista = typeof raw === 'string' ? JSON.parse(raw) : (Array.isArray(raw) ? raw : []); } catch(e) { lista = []; }
const ctx = $('Roteador').item.json;
const from = ctx.from, instance = ctx.instance, nome = ctx.moradorNome;
if (lista.length === 0) {
  return [{ json: { from, instance, msg: `📭 *Sem encomendas*\n\nOlá, ${nome}! Não há encomendas aguardando retirada.\n\nAssim que chegar algo, avisamos! 😊` } }];
}
let t = `📦 *Suas Encomendas* (${lista.length})\n\n`;
lista.forEach((e, i) => {
  const dt = e.data_recebimento ? new Date(e.data_recebimento).toLocaleString('pt-BR', { day:'2-digit', month:'2-digit', year:'numeric', hour:'2-digit', minute:'2-digit' }) : '?';
  t += `*${i+1}. ${e.descricao}*\n   📅 ${dt}\n\n`;
});
t += `_Retire na portaria com documento. 🏢_\n\nPara confirmar retirada envie: *RETIREI 1*`;
return [{ json: { from, instance, msg: t } }];

const ctx = $('Roteador').item.json;
const texto = (ctx.texto ?? '').trim();
const indice = parseInt(texto.toUpperCase().split(' ')[1] ?? '0', 10);
if (isNaN(indice) || indice < 1) {
  return [{ json: { from: ctx.from, instance: ctx.instance, moradorId: ctx.moradorId, moradorNome: ctx.moradorNome, indice: 0, erroFormato: true } }];
}
return [{ json: { from: ctx.from, instance: ctx.instance, moradorId: ctx.moradorId, moradorNome: ctx.moradorNome, indice, erroFormato: false } }];

const raw = $input.first().json.data ?? $input.first().json;
let lista = [];
try { lista = typeof raw === 'string' ? JSON.parse(raw) : (Array.isArray(raw) ? raw : []); } catch(e) { lista = []; }
const ctx = $('Parsear RETIREI').item.json;
if (lista.length === 0) {
  return [{ json: { from: ctx.from, instance: ctx.instance, moradorNome: ctx.moradorNome, encId: null, encDesc: null, naoAchada: true } }];
}
return [{ json: { from: ctx.from, instance: ctx.instance, moradorNome: ctx.moradorNome, encId: lista[0].id, encDesc: lista[0].descricao, naoAchada: false } }];

const d = $json;
const texto = (d.texto ?? '').trim();
const etapa = d.sessaoEtapa;
const dados = d.sessaoDados ?? {};

const base = {
  from: d.from,
  instance: d.instance,
  moradorId: d.moradorId,
  moradorNome: d.moradorNome,
  moradorApto: d.moradorApto,
  moradorBloco: d.moradorBloco,
};

if (texto.toUpperCase() === 'CANCELAR') {
  return [{ json: { ...base, ok: true, prox: null, nd: '{}', resp: 'Cadastro de visitante cancelado.\n\nDigite *menu* para voltar ao menu principal.' } }];
}

let prox;
let nd = { ...dados };
let resp;
let ok = false;

if (!etapa || !etapa.startsWith('visitante_')) {
  prox = 'visitante_nome';
  nd = {};
  resp = '🚗 *Autorizar Visitante*\n\nQual é o nome completo do visitante?\n\n_Para cancelar, digite CANCELAR._';
} else if (etapa === 'visitante_nome') {
  if (texto.length < 3) {
    prox = 'visitante_nome';
    resp = 'Por favor, informe o nome completo do visitante.';
  } else {
    nd.nome = texto;
    prox = 'visitante_documento';
    resp = 'Informe o RG/CPF do visitante.\n\nSe não tiver, digite *PULAR*.';
  }
} else if (etapa === 'visitante_documento') {
  nd.documento = /^pular$/i.test(texto) ? null : texto;
  prox = 'visitante_data';
  resp = 'Para qual dia e horário deseja autorizar?\n\nExemplo: *hoje 19h* ou *25/05 14h*.';
} else if (etapa === 'visitante_data') {
  if (texto.length < 3) {
    prox = 'visitante_data';
    resp = 'Informe o dia e horário da visita.';
  } else {
    nd.data_hora = texto;
    prox = 'visitante_motivo';
    resp = 'Qual é o motivo da visita?\n\nExemplo: entrega, familiar, prestador de serviço.';
  }
} else if (etapa === 'visitante_motivo') {
  nd.motivo = texto || 'Não informado';
  ok = true;
  prox = null;
  resp = '✅ *Visitante autorizado!*\n\n' +
    '*Visitante:* ' + nd.nome + '\n' +
    '*Documento:* ' + (nd.documento ?? 'Não informado') + '\n' +
    '*Data/Hora:* ' + nd.data_hora + '\n' +
    '*Motivo:* ' + nd.motivo + '\n\n' +
    'A portaria já pode conferir estes dados pelo atendimento.';
} else {
  prox = 'visitante_nome';
  nd = {};
  resp = 'Vamos começar de novo. Qual é o nome completo do visitante?';
}

return [{ json: { ...base, ok, prox, nd: JSON.stringify(nd), resp } }];

const d = $json;
const texto = (d.texto ?? '').trim();
const etapa = d.sessaoEtapa;
const dados = d.sessaoDados ?? {};

const base = {
  from: d.from,
  instance: d.instance,
  moradorId: d.moradorId,
  moradorNome: d.moradorNome,
  moradorApto: d.moradorApto,
  moradorBloco: d.moradorBloco,
};

if (texto.toUpperCase() === 'CANCELAR') {
  return [{ json: { ...base, ok: true, prox: null, nd: '{}', resp: 'Registro de ocorrência cancelado.\n\nDigite *menu* para voltar ao menu principal.' } }];
}

let prox;
let nd = { ...dados };
let resp;
let ok = false;

if (!etapa || !etapa.startsWith('ocorrencia_')) {
  prox = 'ocorrencia_tipo';
  nd = {};
  resp = '⚠️ *Registrar Ocorrência*\n\nQual é o tipo da ocorrência?\n\nExemplos: barulho, vazamento, segurança, manutenção.\n\n_Para cancelar, digite CANCELAR._';
} else if (etapa === 'ocorrencia_tipo') {
  if (texto.length < 3) {
    prox = 'ocorrencia_tipo';
    resp = 'Informe o tipo da ocorrência.';
  } else {
    nd.tipo = texto;
    prox = 'ocorrencia_local';
    resp = 'Onde ocorreu?\n\nExemplo: garagem, bloco A, hall, apartamento 101.';
  }
} else if (etapa === 'ocorrencia_local') {
  if (texto.length < 2) {
    prox = 'ocorrencia_local';
    resp = 'Informe o local da ocorrência.';
  } else {
    nd.local = texto;
    prox = 'ocorrencia_descricao';
    resp = 'Descreva a ocorrência com os detalhes principais.';
  }
} else if (etapa === 'ocorrencia_descricao') {
  if (texto.length < 5) {
    prox = 'ocorrencia_descricao';
    resp = 'Descreva a ocorrência com um pouco mais de detalhe.';
  } else {
    nd.descricao = texto;
    prox = 'ocorrencia_urgencia';
    resp = 'Qual é a urgência?\n\nResponda: *baixa*, *média* ou *alta*.';
  }
} else if (etapa === 'ocorrencia_urgencia') {
  const normalizada = texto.toLowerCase();
  nd.urgencia = ['baixa', 'media', 'média', 'alta'].includes(normalizada) ? texto : 'Não informada';
  ok = true;
  prox = null;
  resp = '✅ *Ocorrência registrada!*\n\n' +
    '*Tipo:* ' + nd.tipo + '\n' +
    '*Local:* ' + nd.local + '\n' +
    '*Urgência:* ' + nd.urgencia + '\n' +
    '*Descrição:* ' + nd.descricao + '\n\n' +
    'Protocolo: OC-' + Date.now().toString().slice(-6);
} else {
  prox = 'ocorrencia_tipo';
  nd = {};
  resp = 'Vamos começar de novo. Qual é o tipo da ocorrência?';
}

return [{ json: { ...base, ok, prox, nd: JSON.stringify(nd), resp } }];

const d = $json;
const texto = (d.texto ?? '').trim();
const etapa = d.sessaoEtapa;
const dados = d.sessaoDados ?? {};
const base = { from: d.from, instance: d.instance, moradorId: d.moradorId, moradorNome: d.moradorNome, moradorApto: d.moradorApto, moradorBloco: d.moradorBloco };
if (texto.toUpperCase() === 'CANCELAR') {
  return [{ json: { ...base, ok: true, prox: null, nd: '{}', resp: 'Solicitação de serviço cancelada.\n\nDigite *menu* para voltar ao menu principal.' } }];
}
let prox, nd = { ...dados }, resp, ok = false;
if (!etapa || !etapa.startsWith('servico_')) {
  prox = 'servico_tipo'; nd = {};
  resp = '🔧 *Solicitar Serviço*\n\nQual é o tipo de serviço?\n\nExemplos: elétrica, encanamento, limpeza, manutenção, jardinagem.\n\n_Para cancelar, digite CANCELAR._';
} else if (etapa === 'servico_tipo') {
  if (texto.length < 3) { prox = 'servico_tipo'; resp = 'Informe o tipo de serviço.'; }
  else { nd.tipo = texto; prox = 'servico_local'; resp = 'Onde precisa do serviço?\n\nExemplo: Ap. 304, hall de entrada, garagem.'; }
} else if (etapa === 'servico_local') {
  if (texto.length < 2) { prox = 'servico_local'; resp = 'Informe o local.'; }
  else { nd.local = texto; prox = 'servico_descricao'; resp = 'Descreva o problema ou o serviço necessário.'; }
} else if (etapa === 'servico_descricao') {
  if (texto.length < 5) { prox = 'servico_descricao'; resp = 'Descreva com um pouco mais de detalhe.'; }
  else { nd.descricao = texto; prox = 'servico_urgencia'; resp = 'Qual é a urgência?\n\nResponda: *baixa*, *média* ou *alta*.'; }
} else if (etapa === 'servico_urgencia') {
  const norm = texto.toLowerCase();
  nd.urgencia = ['baixa','media','média','alta'].includes(norm) ? texto : 'média';
  ok = true; prox = null;
  resp = '✅ *Serviço solicitado!*\n\n*Tipo:* ' + nd.tipo + '\n*Local:* ' + nd.local + '\n*Urgência:* ' + nd.urgencia + '\n*Descrição:* ' + nd.descricao + '\n\nProtocolo: SV-' + Date.now().toString().slice(-6) + '\nA equipe de manutenção será acionada em breve! 🔧';
} else {
  prox = 'servico_tipo'; nd = {};
  resp = 'Vamos começar de novo. Qual é o tipo de serviço?';
}
return [{ json: { ...base, ok, prox, nd: JSON.stringify(nd), resp } }];

const d = $json;
const texto = (d.texto ?? '').trim();
const etapa = d.sessaoEtapa;
const dados = d.sessaoDados ?? {};
const base = { from: d.from, instance: d.instance, moradorId: d.moradorId, moradorNome: d.moradorNome, moradorApto: d.moradorApto, moradorBloco: d.moradorBloco };
if (texto.toUpperCase() === 'CANCELAR') {
  return [{ json: { ...base, ok: true, prox: null, nd: '{}', resp: 'Reserva cancelada.\n\nDigite *menu* para voltar ao menu principal.' } }];
}
let prox, nd = { ...dados }, resp, ok = false;
const areas = { '1': 'Salão de Festas', '2': 'Churrasqueira', '3': 'Quadra Esportiva' };
if (!etapa || !etapa.startsWith('reserva_')) {
  prox = 'reserva_area'; nd = {};
  resp = '📅 *Reservar Área Comum*\n\nQual área deseja reservar?\n\n1️⃣  Salão de Festas\n2️⃣  Churrasqueira\n3️⃣  Quadra Esportiva\n\n_Para cancelar, digite CANCELAR._';
} else if (etapa === 'reserva_area') {
  const area = areas[texto];
  if (!area) { prox = 'reserva_area'; resp = 'Opção inválida. Digite 1, 2 ou 3 para escolher a área.'; }
  else { nd.area = area; prox = 'reserva_data'; resp = 'Qual data deseja reservar a *' + area + '*?\n\nFormato: DD/MM/AAAA (ex: 25/07/2026)'; }
} else if (etapa === 'reserva_data') {
  if (!/^\d{2}\/\d{2}\/\d{4}$/.test(texto)) { prox = 'reserva_data'; resp = 'Data inválida. Use o formato DD/MM/AAAA (ex: 25/07/2026).'; }
  else { nd.data = texto; prox = 'reserva_horario'; resp = 'Qual horário? Informe o início e fim.\n\nExemplo: 14h às 18h'; }
} else if (etapa === 'reserva_horario') {
  if (texto.length < 3) { prox = 'reserva_horario'; resp = 'Informe o horário.'; }
  else {
    nd.horario = texto; ok = true; prox = null;
    const [d2, m, y] = nd.data.split('/');
    const dataIso = y + '-' + m + '-' + d2;
    nd.dataIso = dataIso;
    resp = '✅ *Reserva solicitada!*\n\n📍 *Área:* ' + nd.area + '\n📅 *Data:* ' + nd.data + '\n🕐 *Horário:* ' + nd.horario + '\n\nSua reserva está *aguardando aprovação* da administração. Você será notificado assim que for confirmada!';
  }
} else {
  prox = 'reserva_area'; nd = {};
  resp = 'Vamos começar de novo. Qual área deseja reservar?\n\n1️⃣  Salão de Festas\n2️⃣  Churrasqueira\n3️⃣  Quadra Esportiva';
}
return [{ json: { ...base, ok, prox, nd: JSON.stringify(nd), resp } }];
